import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.ePeAWSvT.js";const n="/assets/build-data-models.BnoiHwf4.png",s="/assets/modal-data-model-add.Cz2idTfq.png",r="/assets/modal-data-model-foreign-key-tab.RE-dGjFF.png",l="/assets/modal-data-model-transaction-types-tab.CbX0j69g.png",d="/assets/modal-data-model-edit.DeLPnYVR.png",f=JSON.parse('{"title":"Data Models","description":"","frontmatter":{},"headers":[],"relativePath":"guide/build-data-models.md","filePath":"guide/build-data-models.md"}'),c={name:"guide/build-data-models.md"};function p(h,e,m,u,g,y){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="data-models" tabindex="-1">Data Models <a class="header-anchor" href="#data-models" aria-label="Permalink to &quot;Data Models&quot;">​</a></h1><p>Data Models are built by identifying and defining Schema Definitions and assigning Schema Properties to each. A Schema Definition is the whole of the data you are trying to define, while the components that make up that data are Schema Properties. For example, a Schema Definition could be <em>Customer</em>, while <em>Customer Name</em> is a single Schema Property.</p><p>You can define Schema Properties via three methods: Simple, Foreign Key, and List. You can add multiple Properties, as well as multiple Property Types, to a single Schema Definition.</p><p><img src="'+n+'" alt="Data Models Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Entity Types</strong> — Define schemas for Customer, Sales Order, Product, Vendor, and other entity types</li><li><strong>Property Maps</strong> — Configure properties and their mapping types (Property, ForeignKey, CustomData)</li><li><strong>Relationships</strong> — Define foreign key relationships between entities</li><li><strong>List Properties</strong> — Support for nested/child entity collections (parent/child hierarchies)</li><li><strong>Transaction Types</strong> — Specify supported operations that pair Publishers and Subscribers</li><li><strong>Extra Primary Keys</strong> — Handle edge cases where entities exist in multiple tables</li></ul><p>Each Schema Property can also be edited to include:</p><ul><li>A <strong>Description</strong> for additional context (e.g. distinguishing between multiple Inventory schemas with descriptions like <em>Picked</em> or <em>Received</em>)</li><li>A <strong>Related Data</strong> flag, which makes this property available to related entities during sync events (e.g. a Customer&#39;s name can be carried onto a Sales Order). See <a href="./reference-related-data.html">Related Data</a> for details on how this works.</li><li><strong>Chat Form Controls</strong> that help build the AI model</li></ul><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><ul><li>Develop naming convention standards early (consistent case, hyphen usage, etc.)</li><li>Use Simple Schema Definitions when available</li></ul></div><h2 id="schema-types" tabindex="-1">Schema Types <a class="header-anchor" href="#schema-types" aria-label="Permalink to &quot;Schema Types&quot;">​</a></h2><h3 id="simple-schema-definition" tabindex="-1">Simple Schema Definition <a class="header-anchor" href="#simple-schema-definition" aria-label="Permalink to &quot;Simple Schema Definition&quot;">​</a></h3><p>A Simple Schema Definition is a single value-to-value transaction. It represents data that is both common and static, meaning it applies to all (or most) of your data systems and is unlikely to change between systems (e.g. Customer Name). When defining Simple Schemas, your Schema Definition must align and link to a property defined by the <a href="./reference-common-model.html">Common Model</a> (a Central Property).</p><h3 id="extra-primary-keys" tabindex="-1">Extra Primary Keys <a class="header-anchor" href="#extra-primary-keys" aria-label="Permalink to &quot;Extra Primary Keys&quot;">​</a></h3><p>Extra Primary Keys are used when the same Entity needs to exist in multiple tables within a given system. For example, Locations or Divisions may have their own database table but also be replicated into a Departments table. This feature is generally only used in edge cases where a system has unique data storage methodologies.</p><h3 id="foreign-key-schema-property" tabindex="-1">Foreign Key Schema Property <a class="header-anchor" href="#foreign-key-schema-property" aria-label="Permalink to &quot;Foreign Key Schema Property&quot;">​</a></h3><p>Foreign Key definitions are references to data that may be different from one system to the next — such as a customer record number in your sales system vs. your billing system. These definitions are customer-built and customized to your specific needs. Some Foreign Key Entity Types will need to be further defined with a Sub-Type (e.g. a Company could be sub-classified as a Customer or Vendor).</p><h3 id="list-schema-property" tabindex="-1">List Schema Property <a class="header-anchor" href="#list-schema-property" aria-label="Permalink to &quot;List Schema Property&quot;">​</a></h3><p>A List Schema is a pointer to another Schema, used for parent/child customizations. For example, an order has a list of line items, and each line item has its own Schema defining Quantity, Amount, Discounts, etc. Any parent/child data should be defined within a List Schema.</p><h2 id="transaction-types" tabindex="-1">Transaction Types <a class="header-anchor" href="#transaction-types" aria-label="Permalink to &quot;Transaction Types&quot;">​</a></h2><p>Transaction Types are events that become part of the Schema, physically pairing a Publisher and a Subscriber. They identify the actions you want to take on the data, such as <em>Save Customer</em> or <em>Delete Customer</em>. Transaction Types tie directly to a Schema Definition, enabling users to select those actions when adding Endpoints.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Each Schema Definition must be assigned one or more Transaction Types. The Transaction Types created during this process will become part of a selectable list when adding Endpoints to map your data.</p></div><h2 id="add-a-schema-definition" tabindex="-1">Add a Schema Definition <a class="header-anchor" href="#add-a-schema-definition" aria-label="Permalink to &quot;Add a Schema Definition&quot;">​</a></h2><p><img src="'+s+'" alt="Add Schema Definition Modal"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Models</strong> from the main menu.</p></li><li><p>Select <strong>+ Add</strong>.</p></li><li><p>Select an <strong>Entity Type</strong>; and as needed, enter a <strong>Sub-Type</strong>.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Once created, the Entity Type and Sub-Type cannot be modified.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>A Sub-Type can be defined for several pre-determined Entity Types and adds a more precise attribute to that Schema. They allow Schemas defined by the same Entity Type to be cataloged into more precise groupings, enabling the Common Model to group relationships in the database even when the data is housed in different systems.</p><p>For example, a Schema with the Entity Type &quot;Company&quot; may be further classified into Sub-Types &quot;Vendor&quot; and &quot;Customer.&quot; The Sub-Type discloses which relationship this particular Schema refers to.</p><ul><li>The Sub-Type field will appear only for supported Entity Types</li><li>Each Sub-Type must be entered precisely (e.g. <em>Vendor</em> vs <em>vendors</em> will create two separate sub-types)</li><li>When adding a Foreign Key with a new Entity Type, you can select a previously created Sub-Type from the drop-down menu</li></ul></div><ol start="4"><li>Enter a <strong>Schema Definition Name</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Do not add spacing to any field entries.</p></div><ol start="5"><li>Assign Schema Properties to the Definition using one or more of the tabs below:</li></ol><h3 id="adding-a-simple-property" tabindex="-1">Adding a Simple Property <a class="header-anchor" href="#adding-a-simple-property" aria-label="Permalink to &quot;Adding a Simple Property&quot;">​</a></h3><ul><li>Ensure the <strong>Simple</strong> tab is selected</li><li>Select a <strong>Central Property</strong> from the drop-down menu; or toggle <strong>Custom</strong> ON to enter a custom Property</li><li>Select <strong>+ Add</strong> — the Central Property will be added to the table</li><li>Repeat as needed for additional properties</li></ul><div class="info custom-block"><p class="custom-block-title">Example</p><p>You may create a Schema Definition named <em>Customer Schema</em> to define all pertinent company data, including Properties such as <em>Name</em>, <em>PrimaryBillingAddress1</em>, <em>PrimaryBillingAddress2</em>, <em>PrimaryBillingCity</em>, etc.</p></div><h3 id="adding-a-foreign-key-property" tabindex="-1">Adding a Foreign Key Property <a class="header-anchor" href="#adding-a-foreign-key-property" aria-label="Permalink to &quot;Adding a Foreign Key Property&quot;">​</a></h3><p><img src="'+r+'" alt="Foreign Key Tab"></p><ul><li>Select the <strong>Foreign Key</strong> tab</li><li>Select an <strong>Entity Type</strong> from the drop-down menu; and if applicable, select a <strong>Sub-Type</strong></li><li>Enter a <strong>Name</strong> in the text field</li><li>Select <strong>+ Add</strong></li><li>Repeat as needed</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The Sub-Type menu will only appear for applicable Entity Types.</p></div><h3 id="adding-extra-primary-keys" tabindex="-1">Adding Extra Primary Keys <a class="header-anchor" href="#adding-extra-primary-keys" aria-label="Permalink to &quot;Adding Extra Primary Keys&quot;">​</a></h3><ul><li>Select the <strong>Extra Primary Keys</strong> tab</li><li>Enter a <strong>Key Name</strong>; then select <strong>+ Add</strong></li></ul><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>When naming Extra Primary Keys, give them a name representative of what the additional table in the system is called.</p></div><h3 id="adding-a-list-property" tabindex="-1">Adding a List Property <a class="header-anchor" href="#adding-a-list-property" aria-label="Permalink to &quot;Adding a List Property&quot;">​</a></h3><ul><li>Select the <strong>List</strong> tab</li><li>Select a <strong>List Property</strong> from the drop-down menu</li><li>Select a <strong>Data Model</strong> from the drop-down menu</li><li>Select <strong>+ Add</strong></li><li>Repeat as needed</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Only selectable options will be shown. The List Property menu is filtered based on your Entity Type selection, and the Schema menu is filtered based on your List Property selection.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>You can add multiple Schema Properties of multiple types to a single Schema Definition. However, to create a List Property, you must first define each list item as its own Schema Definition.</p></div><ol start="6"><li>Select the <strong>Transaction Types</strong> tab.</li></ol><p><img src="'+l+'" alt="Transaction Types Tab"></p><ol start="7"><li>Enter a <strong>Transaction Type</strong> in the text field; then select <strong>+ Add</strong>. Repeat until all necessary Transaction Types are added.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li>Transaction Type is a freeform text field to describe the event name, ultimately linking Publishers and Subscribers together. When messages get published under a certain Transaction Type, only subscribers to that Transaction Type will process it.</li><li>Multiple Transaction Types can be added to a single Schema Definition for micro-level messaging, publishing the same data in several ways, or targeting/isolating integrations.</li><li>Schema Definitions and Transaction Types can be built incrementally and amended at any time. However, both must be completed prior to mapping Endpoints.</li></ul></div><ol start="8"><li>When finished, select <strong>Save</strong>.</li></ol><h2 id="edit-a-schema-definition" tabindex="-1">Edit a Schema Definition <a class="header-anchor" href="#edit-a-schema-definition" aria-label="Permalink to &quot;Edit a Schema Definition&quot;">​</a></h2><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Models</strong> from the main menu.</p></li><li><p>Select the <strong>edit</strong> icon in the appropriate Data Model row.</p></li></ol><p><img src="'+d+'" alt="Edit Data Model Modal"></p><ol start="3"><li>Modify the attributes as needed using the operations below:</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Once created, the Entity Type and Sub-Type cannot be modified.</p></div><table tabindex="0"><thead><tr><th>To</th><th>Do this</th></tr></thead><tbody><tr><td><strong>Edit the Schema Definition Name</strong></td><td>Enter a new Schema Definition Name in the text field</td></tr><tr><td><strong>Add a Schema Property</strong></td><td>Follow the instructions in the Add a Schema Definition section above</td></tr><tr><td><strong>Add a Schema Property Description</strong></td><td>On the Simple tab, select the edit icon in the appropriate row. Enter the Description, then select Save</td></tr><tr><td><strong>Toggle Related Data</strong></td><td>On the Simple tab, select the edit icon. Toggle ON the Related Data switch, then select Save. This makes the property available as <a href="./reference-related-data.html">Related Data</a> on entities that reference this schema via a foreign key.</td></tr><tr><td><strong>Include in Chat Form Control</strong></td><td>On the Simple tab, select the edit icon. Toggle ON Chat Form Control, choose a Control Type, enter a Label and Default Value, toggle Required as needed, enter a Form Sequence and Group Name, then select Save</td></tr><tr><td><strong>Delete a Schema Property or Transaction Type</strong></td><td>Select the appropriate tab, then select the delete icon in the appropriate row</td></tr></tbody></table><ol start="4"><li>When finished, select <strong>Save</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To discard all changes and exit edit mode, select <strong>Cancel</strong>. To reset all edits made during this session and remain in edit mode, select <strong>Reset</strong>.</p></div><h2 id="delete-a-data-model" tabindex="-1">Delete a Data Model <a class="header-anchor" href="#delete-a-data-model" aria-label="Permalink to &quot;Delete a Data Model&quot;">​</a></h2><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Models</strong> from the main menu.</p></li><li><p>Select the <strong>delete</strong> icon in the appropriate row.</p></li><li><p>Select <strong>OK</strong> to confirm.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a Schema Definition cannot be undone; you must recreate it if needed.</p></div><h2 id="host-type-extensions" tabindex="-1">Host Type Extensions <a class="header-anchor" href="#host-type-extensions" aria-label="Permalink to &quot;Host Type Extensions&quot;">​</a></h2><details class="details custom-block"><summary>Advanced Tool</summary><p><a href="./build-custom-extensions.html">Host Type Extensions</a> enable developers to take a pre-built Central Connector and extend it for specific needs (i.e. build your own override). The <em>Host Type</em> references the location in the cloud where your customizations are hosted to run.</p><p>Central supports three deployment methods:</p><ol><li><strong>Embedded</strong> — The connection runs embedded in the agent, usually for network purposes. If Central needs to get data from within a company&#39;s network, the agent accesses the data sources directly.</li><li><strong>Cloud-based</strong> — The connection runs via a cloud-based Connector. Central runs on Microsoft Azure and distributes data via proxy method. This is the typical method employed by Central.</li><li><strong>Custom</strong> — The connection runs via host type extensions built and customized by the developer. You build a company-specific space in the cloud (e.g. Google Cloud, AWS) to host a Connector and override functionality for your specific needs.</li></ol></details><h3 id="add-a-host-type-extension" tabindex="-1">Add a Host Type Extension <a class="header-anchor" href="#add-a-host-type-extension" aria-label="Permalink to &quot;Add a Host Type Extension&quot;">​</a></h3><ol><li>Select <strong>Build</strong> &gt; <strong>Custom Extensions</strong> from the main menu.</li><li>Select <strong>+ Add</strong>.</li><li>Enter a <strong>Name</strong> in the text field.</li><li>Enter the appropriate <strong>Secure Settings</strong>.</li><li>Select <strong>Save</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To view entered secure settings data, select <strong>Hide All</strong> or <strong>View All</strong>, or toggle the View/Hide icon in the entry field.</p></div><h3 id="edit-a-host-type-extension" tabindex="-1">Edit a Host Type Extension <a class="header-anchor" href="#edit-a-host-type-extension" aria-label="Permalink to &quot;Edit a Host Type Extension&quot;">​</a></h3><ol><li>Select <strong>Build</strong> &gt; <strong>Custom Extensions</strong> from the main menu.</li><li>Select the <strong>edit</strong> icon in the appropriate row.</li><li>Modify the <strong>Name</strong> and/or <strong>Secure Settings</strong> as needed.</li><li>Select <strong>Save</strong>.</li></ol><h3 id="delete-a-host-type-extension" tabindex="-1">Delete a Host Type Extension <a class="header-anchor" href="#delete-a-host-type-extension" aria-label="Permalink to &quot;Delete a Host Type Extension&quot;">​</a></h3><ol><li>Select <strong>Build</strong> &gt; <strong>Custom Extensions</strong> from the main menu.</li><li>Select the <strong>delete</strong> icon in the appropriate row.</li><li>Select <strong>OK</strong> to confirm.</li></ol>',68)])])}const S=t(c,[["render",p]]);export{f as __pageData,S as default};
